(self.webpackChunkvuepress_blog=self.webpackChunkvuepress_blog||[]).push([[4607],{607:(n,s,a)=>{"use strict";a.r(s),a.d(s,{data:()=>e});const e={key:"v-ddf72cb6",path:"/pages/javascript/es6/",title:"",lang:"zh-CN",frontmatter:{},excerpt:"",headers:[{level:3,title:"Symbol使用技巧",slug:"symbol使用技巧",children:[]},{level:3,title:"flatMap",slug:"flatmap",children:[]},{level:3,title:"WeakMap 弱引用的只是键名，而不是键值。键值依然是正常引用",slug:"weakmap-弱引用的只是键名-而不是键值。键值依然是正常引用",children:[]},{level:3,title:"输出结果",slug:"输出结果",children:[]},{level:3,title:"class类无法遍历它实例原型链上的属性和方法",slug:"class类无法遍历它实例原型链上的属性和方法",children:[]},{level:3,title:"new.target",slug:"new-target",children:[]}],filePathRelative:"pages/javascript/es6/README.md",git:{updatedTime:170559183e4,contributors:[{name:"COOKIES-LGL",email:"1344714332@qq.com",commits:4},{name:"guilin.li",email:"1344714332@qq.com",commits:2}]}}},6377:(n,s,a)=>{"use strict";a.r(s),a.d(s,{default:()=>t});const e=(0,a(6252).uE)('<h3 id="symbol使用技巧"><a class="header-anchor" href="#symbol使用技巧">#</a> Symbol使用技巧</h3><div class="custom-container tip"><p class="custom-container-title">TIP</p><p>symbol 作为对象的属性无法通过.运算符获取,需要使用[symbol]</p></div><div class="custom-container tip"><p class="custom-container-title">TIP</p><p>全局共享Symbol let a = Symbol.for(&quot;a&quot;) let b = Symbol.for(&quot;a&quot;) a === b // true Symbol.keyFor(a) 可以通过变量名查询该变量名对应的Symbol是否在全局注册表中</p></div><div class="custom-container tip"><p class="custom-container-title">TIP</p><p>我们还可以通过更改内置Symbol值对应的方法来达到更改外部方法作用的效果。 class demo {    static <a href="item">Symbol.hasInstance</a> {        return item === &quot;猪痞恶霸&quot;   } } &quot;猪痞恶霸&quot; instanceof demo // true Symbol.hasInstance对应的外部方法是instanceof，这个大家熟悉吧，经常用于判断类型。而在上面的代码片段中，我创建了一个demo类，并重写了Symbol.hasInstance，所以其对应的instanceof行为也会发生改变，其内部的机制是这样的：当我们调用instanceof方法的时候，内部对应调用Symbol.hasInstance对应的方法即return item === &quot;猪痞恶霸&quot;</p></div><h3 id="flatmap"><a class="header-anchor" href="#flatmap">#</a> flatMap</h3><p>使用这个内置方法代替filter and map</p><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code><span class="token keyword">const</span> arr1 <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">2</span><span class="token punctuation">,</span> <span class="token number">1</span><span class="token punctuation">]</span><span class="token punctuation">;</span>\n\n<span class="token keyword">const</span> result <span class="token operator">=</span> arr1<span class="token punctuation">.</span><span class="token function">flatMap</span><span class="token punctuation">(</span><span class="token punctuation">(</span><span class="token parameter">num</span><span class="token punctuation">)</span> <span class="token operator">=&gt;</span> <span class="token punctuation">(</span>num <span class="token operator">===</span> <span class="token number">2</span> <span class="token operator">?</span> <span class="token punctuation">[</span><span class="token number">2</span><span class="token punctuation">,</span> <span class="token number">2</span><span class="token punctuation">]</span> <span class="token operator">:</span> <span class="token number">1</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span>\n\nconsole<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>result<span class="token punctuation">)</span><span class="token punctuation">;</span>\n<span class="token comment">// Expected output: Array [1, 2, 2, 1]</span>\n\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><h3 id="weakmap-弱引用的只是键名-而不是键值。键值依然是正常引用"><a class="header-anchor" href="#weakmap-弱引用的只是键名-而不是键值。键值依然是正常引用">#</a> WeakMap 弱引用的只是键名，而不是键值。键值依然是正常引用</h3><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code><span class="token keyword">const</span> wm <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">WeakMap</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>\n<span class="token keyword">let</span> key <span class="token operator">=</span> <span class="token punctuation">{</span><span class="token punctuation">}</span><span class="token punctuation">;</span>\n<span class="token keyword">let</span> obj <span class="token operator">=</span> <span class="token punctuation">{</span>foo<span class="token operator">:</span> <span class="token number">1</span><span class="token punctuation">}</span><span class="token punctuation">;</span>\n\nwm<span class="token punctuation">.</span><span class="token function">set</span><span class="token punctuation">(</span>key<span class="token punctuation">,</span> obj<span class="token punctuation">)</span><span class="token punctuation">;</span>\nobj <span class="token operator">=</span> <span class="token keyword">null</span><span class="token punctuation">;</span>\nwm<span class="token punctuation">.</span><span class="token function">get</span><span class="token punctuation">(</span>key<span class="token punctuation">)</span>\n<span class="token comment">// Object {foo: 1}</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><h3 id="输出结果"><a class="header-anchor" href="#输出结果">#</a> 输出结果</h3><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>Promise.resolve().then(() =&gt; {\n    return Promise.resolve(4);\n})\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>核心就是会比正常的return一个非Promise的值时，多两个微任务.then().then()</p><h3 id="class类无法遍历它实例原型链上的属性和方法"><a class="header-anchor" href="#class类无法遍历它实例原型链上的属性和方法">#</a> class类无法遍历它实例原型链上的属性和方法</h3><h3 id="new-target"><a class="header-anchor" href="#new-target">#</a> new.target</h3><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code><span class="token comment">// new.target属性允许你检测函数或构造方法是否是通过new运算符被调用的</span>\n<span class="token keyword">function</span> <span class="token function">Foo</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>\n  <span class="token keyword">if</span> <span class="token punctuation">(</span><span class="token operator">!</span><span class="token keyword">new</span><span class="token punctuation">.</span>target<span class="token punctuation">)</span> <span class="token keyword">throw</span> <span class="token string">&quot;Foo() must be called with new&quot;</span><span class="token punctuation">;</span>\n  console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token string">&quot;Foo instantiated with new&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>\n<span class="token punctuation">}</span>\n\n<span class="token function">Foo</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// throws &quot;Foo() must be called with new&quot;</span>\n<span class="token keyword">new</span> <span class="token class-name">Foo</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// logs &quot;Foo instantiated with new&quot;</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><p>TODO 141</p>',16),t={render:function(n,s){return e}}}}]);